// MARK: - AppDeepLink
enum AppDeepLink {
    case profile(id: String)
    case paymentConfirmation
    case adminSettings
    case unknown

    init(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            self = .unknown
            return
        }

        let pathComponents = components.path.split(separator: "/").map(String.init)

        if pathComponents.count >= 1 {
            switch pathComponents[0] {
            case "profile":
                if pathComponents.count >= 2, let id = Int(pathComponents[1]) {
                    self = .profile(id: String(id))
                } else {
                    self = .unknown
                }
            case "payment":
                if pathComponents.count >= 2 && pathComponents[1] == "confirm" {
                    self = .paymentConfirmation
                } else {
                    self = .unknown
                }
            case "admin":
                if pathComponents.count >= 2 && pathComponents[1] == "settings" {
                    self = .adminSettings
                } else {
                    self = .unknown
                }
            default:
                self = .unknown
            }
        } else {
            self = .unknown
        }
    }
}

// MARK: - AppNavigator (Protocol)
protocol AppNavigator {
    func navigate(to deepLink: AppDeepLink)
}

