        navigationController.didMove(toParent: self)
        navigationController.view.frame = view.bounds
        navigationController.view.autoresizingMask = [.flexibleWidth, .flexibleHeight]

        // Initial view if no deep link
        let homeVC = UIViewController()
        homeVC.view.backgroundColor = .systemBackground
        homeVC.title = "Home"
        navigationController.setViewControllers([homeVC], animated: false)
    }

    func navigate(to deepLink: AppDeepLink) {
        // Pop to root before navigating to ensure clean state or handle existing stacks
        navigationController.popToRootViewController(animated: false)

        switch deepLink {
        case .profile(let id):
            let profileVC = ProfileViewController(profileId: id)
            navigationController.pushViewController(profileVC, animated: true)
        case .paymentConfirmation:
            let paymentVC = PaymentConfirmationViewController()
