// MARK: - SceneDelegate (Handles Universal Links)
class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?
    var appNavigator: AppNavigator? // Make it a protocol type

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }

        let window = UIWindow(windowScene: windowScene)
        let rootVC = RootViewController() // Instantiate your root view controller
        window.rootViewController = rootVC
        self.appNavigator = rootVC // Assign the rootVC as the navigator
        self.window = window
        window.makeKeyAndVisible()

        // Handle deep links from the launch options
        if let userActivity = connectionOptions.userActivities.first(where: { $0.activityType == NSUserActivityTypeBrowsingWeb }),
           let url = userActivity.webpageURL {
            handleUniversalLink(url)
        }
    }

    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        // Handle deep links when the app is already running or resumed
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleUniversalLink(url)
    }

    private func handleUniversalLink(_ url: URL) {
        // Ensure the host matches your universal link domain
        guard url.host == "myapp.com" else {
            // If the host doesn't match, you might want to open it in Safari
            if ["http", "https"].contains(url.scheme?.lowercased() ?? "") {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            return
        }

        let deepLink = AppDeepLink(url: url)
        appNavigator?.navigate(to: deepLink) // Use the navigator to handle the deep link
    }
}

